#include<bits/stdc++.h>
using namespace std;

int main(){
    int n,q,p;
    cin>>n>>p>>q;
    while(n--){
        int x,y;
        cin>>x>>y;
        if(x==y){
            cout<<0;
        }else if(x==1||y==1){
            cout<<p;
        }else if(__gcd(x,y)==1){
            cout<<min(p,2*q);
        }else{
            cout<<min(q,2*p);
        }
        cout<<"\n";
    }
    return 0;
}
